CSRF_TOKENS = {}

def generate_csrf_token():
    token = secrets.token_urlsafe(32)
    CSRF_TOKENS[token] = datetime.utcnow()
    return token

def validate_csrf_token(token):
    if token not in CSRF_TOKENS:
        return False
    
    token_time = CSRF_TOKENS[token]
    if datetime.utcnow() - token_time > timedelta(minutes=10):
        del CSRF_TOKENS[token]
        return False
    
    del CSRF_TOKENS[token]
    return True

def cleanup_expired_tokens():
    expired = [token for token, timestamp in CSRF_TOKENS.items() 
               if datetime.utcnow() - timestamp > timedelta(minutes=10)]
    for token in expired:
        del CSRF_TOKENS[token]

def verify_password(stored_hash, password, salt=b'salt'):
    computed_hash = hashlib.pbkdf2_hmac('sha256', password.encode(), salt, 100000).hex()
    return hmac.compare_digest(stored_hash, computed_hash)

