def sign_assertion(saml_response_xml, private_key, certificate):
    from cryptography.hazmat.primitives import serialization
    from cryptography.hazmat.backends import default_backend
    
    root = etree.fromstring(saml_response_xml.encode('utf-8'))
    
    namespaces = {
        'samlp': 'urn:oasis:names:tc:SAML:2.0:protocol',
        'saml': 'urn:oasis:names:tc:SAML:2.0:assertion'
    }
    
    assertion = root.find('.//saml:Assertion', namespaces)
    
    if assertion is not None:
        signer = XMLSigner(
            method=signxml.methods.enveloped,
            signature_algorithm='rsa-sha256',
            digest_algorithm='sha256',
            c14n_algorithm='http://www.w3.org/2001/10/xml-exc-c14n#'
        )
        
        signed_assertion = signer.sign(
            assertion,
            key=private_key.encode() if isinstance(private_key, str) else private_key,
            cert=certificate.encode() if isinstance(certificate, str) else certificate
        )
        
        parent = assertion.getparent()
        parent.replace(assertion, signed_assertion)
    
    return etree.tostring(root, encoding='unicode')

