@app.route('/login', methods=['POST'])
def login():
    csrf_token = request.form.get('csrf_token', '')
    
    if not validate_csrf_token(csrf_token):
        return 'Invalid or expired CSRF token', 403
    
    username = request.form.get('username', '')
    password = request.form.get('password', '')
    saml_request = request.form.get('SAMLRequest', '')
    relay_state = request.form.get('RelayState', '')
    
    if username not in VALID_USERS:
        csrf_token = generate_csrf_token()
        return render_template_string(
            LOGIN_TEMPLATE,
            csrf_token=csrf_token,
            saml_request=saml_request,
            relay_state=relay_state,
            error='Invalid credentials'
        )
    
    user = VALID_USERS[username]
    if not verify_password(user['password'], password):
        csrf_token = generate_csrf_token()
        return render_template_string(
            LOGIN_TEMPLATE,
            csrf_token=csrf_token,
            saml_request=saml_request,
            relay_state=relay_state,
            error='Invalid credentials'
        )
    
    try:
        authn_request = OneLogin_Saml2_Utils.decode_base64_and_inflate(saml_request)
        root = etree.fromstring(authn_request.encode('utf-8'))
        request_id = root.get('ID')
        acs_url = root.get('AssertionConsumerServiceURL')
        
        issuer_elem = root.find('.//{urn:oasis:names:tc:SAML:2.0:assertion}Issuer')
        audience = issuer_elem.text if issuer_elem is not None else SAML_SETTINGS['sp']['entityId']
        
        saml_response_xml = generate_saml_response(
            username,
            user['attributes'],
            request_id,
            acs_url,
            audience
        )
        
        private_key = SAML_SETTINGS['idp']['privateKey']
        certificate = SAML_SETTINGS['idp']['x509cert']
        
        if private_key and certificate:
            saml_response_xml = sign_assertion(saml_response_xml, private_key, certificate)
        
        encoded_response = OneLogin_Saml2_Utils.deflate_and_base64_encode(saml_response_xml)
        
        return render_template_string(
            POST_FORM_TEMPLATE,
            acs_url=acs_url,
            saml_response=encoded_response,
            relay_state=relay_state
        )
    except Exception as e:
        return f'Error generating SAML response: {str(e)}', 500

